namespace ProductsApi.Models;

/// <summary>
/// The category a product belongs to.
/// </summary>
public enum Category
{
    Electronics,
    Clothing,
    Food,
    Books
}

namespace ProductsApi.Models;

/// <summary>
/// Represents a product in the catalog.
/// </summary>
public class Product
{
    /// <summary>Unique identifier for the product.</summary>
    public int Id { get; set; }

    /// <summary>Display name of the product.</summary>
    public required string Name { get; set; }

    /// <summary>Price in USD.</summary>
    public decimal Price { get; set; }

    /// <summary>Product category.</summary>
    public Category Category { get; set; }

    /// <summary>Timestamp when the product was created (UTC).</summary>
    public DateTime CreatedAt { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace ProductsApi.Models;

/// <summary>
/// Payload for creating a new product.
/// </summary>
public class CreateProductRequest
{
    /// <summary>Display name of the product.</summary>
    [Required]
    [StringLength(200, MinimumLength = 1)]
    public required string Name { get; set; }

    /// <summary>Price in USD. Must be greater than zero.</summary>
    [Required]
    [Range(0.01, double.MaxValue, ErrorMessage = "Price must be greater than zero.")]
    public decimal Price { get; set; }

    /// <summary>Product category.</summary>
    [Required]
    [EnumDataType(typeof(Category))]
    public Category Category { get; set; }
}

using ProductsApi.Models;

namespace ProductsApi.Services;

/// <summary>
/// Abstraction for product persistence operations.
/// </summary>
public interface IProductService
{
    IReadOnlyList<Product> GetAll();
    Product? GetById(int id);
    Product Create(CreateProductRequest request);
}

using ProductsApi.Models;

namespace ProductsApi.Services;

/// <summary>
/// Thread-safe in-memory implementation of <see cref="IProductService"/>.
/// </summary>
public class InMemoryProductService : IProductService
{
    private readonly List<Product> _products = [];
    private readonly Lock _lock = new();
    private int _nextId = 1;

    public IReadOnlyList<Product> GetAll()
    {
        lock (_lock)
        {
            return _products.ToList().AsReadOnly();
        }
    }

    public Product? GetById(int id)
    {
        lock (_lock)
        {
            return _products.FirstOrDefault(p => p.Id == id);
        }
    }

    public Product Create(CreateProductRequest request)
    {
        lock (_lock)
        {
            var product = new Product
            {
                Id = _nextId++,
                Name = request.Name,
                Price = request.Price,
                Category = request.Category,
                CreatedAt = DateTime.UtcNow
            };

            _products.Add(product);
            return product;
        }
    }
}

using Microsoft.AspNetCore.Http.HttpResults;
using Microsoft.AspNetCore.Mvc;
using ProductsApi.Models;
using ProductsApi.Services;

namespace ProductsApi.Controllers;

/// <summary>
/// Manages the product catalog.
/// </summary>
[ApiController]
[Route("api/[controller]")]
[Produces("application/json")]
public class ProductsController(IProductService productService) : ControllerBase
{
    /// <summary>
    /// Retrieves every product in the catalog.
    /// </summary>
    /// <returns>A list of all products.</returns>
    /// <response code="200">Returns the full product list (may be empty).</response>
    [HttpGet]
    [ProducesResponseType<IReadOnlyList<Product>>(StatusCodes.Status200OK)]
    public IActionResult GetAll()
    {
        return Ok(productService.GetAll());
    }

    /// <summary>
    /// Retrieves a single product by its unique identifier.
    /// </summary>
    /// <param name="id">The product identifier.</param>
    /// <returns>The matching product.</returns>
    /// <response code="200">Returns the requested product.</response>
    /// <response code="404">No product with the given ID exists.</response>
    [HttpGet("{id:int}")]
    [ProducesResponseType<Product>(StatusCodes.Status200OK)]
    [ProducesResponseType<ProblemDetails>(StatusCodes.Status404NotFound)]
    public IActionResult GetById(int id)
    {
        var product = productService.GetById(id);
        if (product is null)
            return NotFound();

        return Ok(product);
    }

    /// <summary>
    /// Creates a new product in the catalog.
    /// </summary>
    /// <param name="request">The product data.</param>
    /// <returns>The newly created product.</returns>
    /// <response code="201">Product created successfully.</response>
    /// <response code="400">Validation failed for the supplied data.</response>
    [HttpPost]
    [ProducesResponseType<Product>(StatusCodes.Status201Created)]
    [ProducesResponseType<ValidationProblemDetails>(StatusCodes.Status400BadRequest)]
    public IActionResult Create([FromBody] CreateProductRequest request)
    {
        var product = productService.Create(request);
        return CreatedAtAction(nameof(GetById), new { id = product.Id }, product);
    }
}

